-- Final additive guards for user references, saved reports, published dashboards, and confidential exports.
alter table public.report_runs add column if not exists contains_confidential boolean not null default false;
create or replace function public.reporting_user_scope_guard() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_table_name in ('report_definitions','dashboard_definitions') and not public.report_member_in_scope(new.owner_id,new.tenant_id,new.organization_id,new.facility_id) then raise exception 'Reporting owner scope mismatch' using errcode='23503'; end if; if tg_table_name='saved_reports' and (new.owner_id<>auth.uid() or not public.report_member_in_scope(new.owner_id,new.tenant_id,new.organization_id,new.facility_id)) then raise exception 'Saved report owner scope mismatch' using errcode='23503'; end if; if tg_table_name='report_runs' and (new.requested_by<>auth.uid() or not public.report_member_in_scope(new.requested_by,new.tenant_id,new.organization_id,new.facility_id)) then raise exception 'Report requester scope mismatch' using errcode='23503'; end if; if tg_table_name='report_exports' and (new.requested_by<>auth.uid() or not public.report_member_in_scope(new.requested_by,new.tenant_id,new.organization_id,new.facility_id)) then raise exception 'Export requester scope mismatch' using errcode='23503'; end if; return new; end $$;
create trigger report_definition_user_scope before insert or update on public.report_definitions for each row execute function public.reporting_user_scope_guard(); create trigger dashboard_user_scope before insert or update on public.dashboard_definitions for each row execute function public.reporting_user_scope_guard(); create trigger saved_report_user_scope before insert or update on public.saved_reports for each row execute function public.reporting_user_scope_guard(); create trigger report_run_user_scope before insert or update on public.report_runs for each row execute function public.reporting_user_scope_guard(); create trigger report_export_user_scope before insert or update on public.report_exports for each row execute function public.reporting_user_scope_guard();
drop policy if exists saved_reports_owner on public.saved_reports; create policy saved_reports_private_read on public.saved_reports for select using(owner_id=auth.uid() and public.can_report('reports.view',tenant_id,organization_id,facility_id));
create or replace function public.create_saved_report(p_version uuid,p_name text,p_filters jsonb default '[]') returns uuid language plpgsql security definer set search_path=public as $$ declare v public.report_versions%rowtype; id uuid; begin select * into v from public.report_versions where id=p_version and status='published'; if not found or not public.can_report('reports.view',v.tenant_id,v.organization_id,v.facility_id) or jsonb_typeof(p_filters)<>'array' or jsonb_array_length(p_filters)>20 or not public.validate_report_definition(jsonb_build_object('filters',p_filters), (select module_key from public.report_definitions where id=v.definition_id)) then raise exception 'Saved report denied'; end if; insert into public.saved_reports(tenant_id,organization_id,facility_id,report_version_id,name,filters,owner_id) values(v.tenant_id,v.organization_id,v.facility_id,v.id,trim(p_name),p_filters,auth.uid()) returning id into id; return id; end $$;
create or replace function public.publish_dashboard(p_dashboard uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.dashboard_definitions%rowtype; begin select * into d from public.dashboard_definitions where id=p_dashboard for update; if not found or d.status<>'approved' or not public.can_report('dashboards.manage',d.tenant_id,d.organization_id,d.facility_id) or exists(select 1 from public.dashboard_widgets w where w.dashboard_id=d.id and (w.widget_type not in ('kpi_card','counter','gauge','line','area','bar','stacked_bar','pie','donut','heatmap','trend','table','top_n','timeline','activity_feed') or w.configuration::text ~* '(javascript|<script|http:|https:|;)' )) then raise exception 'Dashboard publication denied'; end if; perform set_config('app.reporting_controlled','on',true); update public.dashboard_definitions set status='published',updated_at=now(),updated_by=auth.uid() where id=d.id; end $$;
create or replace function public.request_report_export(p_run_id uuid,p_format text,p_language text) returns uuid language plpgsql security definer set search_path=public as $$ declare r public.report_runs%rowtype; id uuid; begin select * into r from public.report_runs where id=p_run_id and requested_by=auth.uid() for update; if not found or r.status<>'completed' or not public.can_report('reports.export',r.tenant_id,r.organization_id,r.facility_id) or (r.contains_confidential and not public.has_platform_permission('reports.export_confidential',r.tenant_id,r.organization_id,r.facility_id)) then raise exception 'Report export denied'; end if; insert into public.report_exports(tenant_id,organization_id,facility_id,report_run_id,format,language,requested_by,expires_at) values(r.tenant_id,r.organization_id,r.facility_id,r.id,p_format,p_language,auth.uid(),now()+interval '24 hours') returning id into id; return id; end $$;
revoke all on function public.reporting_user_scope_guard(),public.create_saved_report(uuid,text,jsonb),public.publish_dashboard(uuid),public.request_report_export(uuid,text,text) from public,anon; grant execute on function public.create_saved_report(uuid,text,jsonb),public.publish_dashboard(uuid),public.request_report_export(uuid,text,text) to authenticated;
